{
var diffuse = inputs.Length > 0 && inputs[0] != null ? inputs[0]! :
        new PixelBuffer(context.TileSize, context.TileSize);

    var normalMap = inputs.Length > 1 && inputs[1] != null ? inputs[1] : null;
    var heightMap = inputs.Length > 2 && inputs[2] != null ? inputs[2] : null;

    var lightType = GetChoice(parameters, "lightType", "directional");
    var lx = GetFloat(parameters, "lightAngleX", -0.5f);
    var ly = GetFloat(parameters, "lightAngleY", -0.5f);
    var lz = GetFloat(parameters, "lightAngleZ", 0.8f);
    var lightColor = GetColor(parameters, "lightColor", System.Windows.Media.Color.FromRgb(255, 240, 220));
    var ambient = GetFloat(parameters, "ambient", 0.3f);
    var specIntensity = GetFloat(parameters, "specIntensity", 0.5f);
    var specPower = GetFloat(parameters, "specPower", 8f);
    var flipNormalY = GetBool(parameters, "flipNormalY", false);

    var lightR = lightColor.R / 255f;
    var lightG = lightColor.G / 255f;
    var lightB = lightColor.B / 255f;

    var size = context.TileSize;
    var output = new PixelBuffer(size, size);

    // Normalize light direction
    var lLen = MathF.Sqrt(lx * lx + ly * ly + lz * lz);
    if (lLen > 0f) { lx /= lLen; ly /= lLen; lz /= lLen; }

    // View direction (from surface toward camera)
    var vx = 0f;
    var vy = 0f;
    var vz = 1f;

    output.ParallelForEachPixel((x, y) =>
    {
        var (dr, dg, db, da) = diffuse.GetPixel(x, y);

        // Get normal from normal map or derive from height map
        float nx, ny, nz;
        if (normalMap != null)
        {
            var (nr, ng, nb, _) = normalMap.GetPixel(x, y);
            nx = nr * 2f - 1f;
            ny = ng * 2f - 1f;
            nz = nb * 2f - 1f;
        }
        else if (heightMap != null)
        {
            // Derive normal from height map gradients
            var hC = SampleHeight(heightMap, x, y);
            var hL = SampleHeight(heightMap, Math.Max(0, x - 1), y);
            var hR = SampleHeight(heightMap, Math.Min(size - 1, x + 1), y);
            var hD = SampleHeight(heightMap, x, Math.Max(0, y - 1));
            var hU = SampleHeight(heightMap, x, Math.Min(size - 1, y + 1));
            var gx = (hR - hL) * 2f;
            var gy = (hU - hD) * 2f;
            var len = MathF.Sqrt(gx * gx + gy * gy + 1f);
            nx = -gx / len;
            ny = -gy / len;
            nz = 1f / len;
        }
        else
        {
            // Default: flat normal facing viewer
            nx = 0f; ny = 0f; nz = 1f;
        }

        if (flipNormalY) ny = -ny;

        // Normalize normal
        var nLen = MathF.Sqrt(nx * nx + ny * ny + nz * nz);
        if (nLen > 0f) { nx /= nLen; ny /= nLen; nz /= nLen; }

        // Diffuse lighting
        var ndotl = nx * lx + ny * ly + nz * lz;
        ndotl = MathF.Max(0f, ndotl);

        // Hemisphere light: blend between sky and ground colors
        float diffuseFactor;
        if (lightType == "hemisphere")
        {
            var hemi = ny * 0.5f + 0.5f;
            diffuseFactor = ambient + (1f - ambient) * hemi * 0.8f;
        }
        else
        {
            diffuseFactor = ambient + (1f - ambient) * ndotl;
        }

        // Specular (Blinn-Phong half-vector)
        var specFactor = 0f;
        if (specIntensity > 0f && ndotl > 0f)
        {
            var hx = lx + vx;
            var hy = ly + vy;
            var hz = lz + vz;
            var hLen = MathF.Sqrt(hx * hx + hy * hy + hz * hz);
            if (hLen > 0f) { hx /= hLen; hy /= hLen; hz /= hLen; }

            var ndoth = nx * hx + ny * hy + nz * hz;
            ndoth = MathF.Max(0f, ndoth);
            specFactor = MathF.Pow(ndoth, specPower) * specIntensity;
        }

        // Point light: distance attenuation (use normalized coords)
        if (lightType == "point")
        {
            var px = (x + 0.5f) / size;
            var py = (y + 0.5f) / size;
            var dx = lx - px;
            var dy = ly - py;
            var dist = MathF.Sqrt(dx * dx + dy * dy + 0.5f);
            var atten = 1f / (1f + dist * dist * 2f);
            diffuseFactor = ambient + (1f - ambient) * ndotl * atten;
        }

        var outR = dr * diffuseFactor * lightR + specFactor * lightR;
        var outG = dg * diffuseFactor * lightG + specFactor * lightG;
        var outB = db * diffuseFactor * lightB + specFactor * lightB;

        output.SetPixel(x, y, Math.Clamp(outR, 0f, 1f), Math.Clamp(outG, 0f, 1f), Math.Clamp(outB, 0f, 1f), da);
    });

    return output;

private static float SampleHeight(PixelBuffer buffer, int x, int y)
{
    x = Math.Clamp(x, 0, buffer.Width - 1);
    y = Math.Clamp(y, 0, buffer.Height - 1);
    var (r, g, b, _) = buffer.GetPixel(x, y);
    return r * 0.299f + g * 0.587f + b * 0.114f;
    }
}
